// Basic Canvas implementation for testing
fabric.Canvas = function(element, options) {
  if (!element) throw new Error('Canvas element is required');

  this.lowerCanvasEl = element;
  this.contextContainer = element.getContext('2d');
  this.width = options.width || 600;
  this.height = options.height || 400;
  this.backgroundColor = options.backgroundColor || 'transparent';
  this._objects = [];
  this._eventListeners = {};

  element.width = this.width;
  element.height = this.height;

  this.renderAll();

  console.log('Fabric Canvas created (minimal implementation):', this.width, 'x', this.height);
  return this;
};

fabric.Canvas.prototype = {
  getWidth: function() { return this.width; },
  getHeight: function() { return this.height; },
  setWidth: function(w) { this.width = w; this.lowerCanvasEl.width = w; },
  setHeight: function(h) { this.height = h; this.lowerCanvasEl.height = h; },
  clear: function() {
    this._objects = [];
    this.contextContainer.clearRect(0, 0, this.width, this.height);
    this.renderAll();
  },
  add: function(obj) {
    this._objects.push(obj);
    this.renderAll();
    this.fire('object:added', {target: obj});
  },
  renderAll: function() {
    var ctx = this.contextContainer;
    ctx.clearRect(0, 0, this.width, this.height);

    if (this.backgroundColor && this.backgroundColor !== 'transparent') {
      ctx.fillStyle = this.backgroundColor;
      ctx.fillRect(0, 0, this.width, this.height);
    }

    for (var i = 0; i < this._objects.length; i++) {
      var obj = this._objects[i];
      if (obj.render) obj.render(ctx);
    }
  },
  on: function(event, handler) {
    if (!this._eventListeners[event]) this._eventListeners[event] = [];
    this._eventListeners[event].push(handler);
  },
  fire: function(event, data) {
    var listeners = this._eventListeners[event];
    if (listeners) {
      for (var i = 0; i < listeners.length; i++) {
        listeners[i](data);
      }
    }
  },
  dispose: function() {
    this._objects = [];
    this._eventListeners = {};
  },
  toDataURL: function(options) {
    var format = options && options.format || 'png';
    var multiplier = options && options.multiplier || 1;

    // Create a temporary canvas for export
    var tempCanvas = document.createElement('canvas');
    tempCanvas.width = this.width * multiplier;
    tempCanvas.height = this.height * multiplier;
    var tempCtx = tempCanvas.getContext('2d');

    // Scale context if multiplier is not 1
    if (multiplier !== 1) {
      tempCtx.scale(multiplier, multiplier);
    }

    // Clear and set background
    tempCtx.clearRect(0, 0, this.width, this.height);
    if (this.backgroundColor && this.backgroundColor !== 'transparent') {
      tempCtx.fillStyle = this.backgroundColor;
      tempCtx.fillRect(0, 0, this.width, this.height);
    }

    // Render all objects
    for (var i = 0; i < this._objects.length; i++) {
      var obj = this._objects[i];
      if (obj.render) obj.render(tempCtx);
    }

    return tempCanvas.toDataURL('image/' + format);
  }
};

// Basic Image class
fabric.Image = {
  fromURL: function(url, callback, options) {
    console.log('[Fabric] Loading image from URL:', url);
    var img = new Image();
    img.crossOrigin = options && options.crossOrigin || 'anonymous';

    img.onload = function() {
      console.log('[Fabric] Image loaded:', img.width, 'x', img.height);
      var fabricImg = {
        width: img.width,
        height: img.height,
        element: img,
        left: 0,
        top: 0,
        scaleX: 1,
        scaleY: 1,
        selectable: true,
        evented: true,

        set: function(props) {
          for (var key in props) {
            this[key] = props[key];
          }
          return this;
        },

        scale: function(value) {
          this.scaleX = value;
          this.scaleY = value;
          return this;
        },

        getScaledWidth: function() {
          return this.width * this.scaleX;
        },

        getScaledHeight: function() {
          return this.height * this.scaleY;
        },

        render: function(ctx) {
          if (this.element) {
            ctx.save();
            ctx.translate(this.left, this.top);
            ctx.scale(this.scaleX, this.scaleY);
            ctx.drawImage(this.element, 0, 0, this.width, this.height);
            ctx.restore();
          }
        }
      };

      console.log('[Fabric] Fabric image object created successfully');
      callback(fabricImg);
    };

    img.onerror = function() {
      console.error('[Fabric] Failed to load image:', url);
      callback(null);
    };

    img.src = url;
  }
};

